formulas.expression:
IF(
    OR(
        ISBLANK({!Get_Holiday_MSG.Holiday_Message__c}),
        NOT({!Get_Holiday_MSG.Is_Active__c})
    ),
    "",
    SUBSTITUTE(
        SUBSTITUTE(
            SUBSTITUTE(
                SUBSTITUTE(
                    SUBSTITUTE(
                        {!Get_Holiday_MSG.Holiday_Message__c},
                        "\r\n\r\n", "<br/><br/>"
                    ),
                    "\n\n", "<br/><br/>"
                ),
                "\r\n", "<br/>"
            ),
            "\n", "<br/>"
        ),
        "\r", "<br/>"
    ) 
)
